"use client";

import { cva, type VariantProps } from "class-variance-authority";
import { useCallback, useState } from "react";
import type * as React from "react";
import { cn } from "@/lib/utils";
import { focusRing, colorTransition, iconMuted } from "@/lib/recipes";

export const toggleVariants = cva(
  [
    "relative inline-flex shrink-0 cursor-pointer items-center justify-center whitespace-nowrap",
    "disabled:pointer-events-none disabled:opacity-50",
    "[&_svg]:pointer-events-none [&_svg]:shrink-0",
    focusRing,
    colorTransition,
  ].join(" "),
  {
    defaultVariants: { size: "md", variant: "tertiary", shape: "square" },
    variants: {
      // Sizes match Button (sm=24, md=32, lg=40) so Toggle sits inline
      // with Button-shaped controls without visual mismatch. Text uses
      // the button family for weight 500 rhythm inside a control.
      size: {
        sm: "h-6 min-w-6 px-2.5 text-button-12 [&_svg:not([class*='size-'])]:size-3.5",
        md: "h-8 min-w-8 px-3.5 text-button-14 [&_svg:not([class*='size-'])]:size-4",
        lg: "h-10 min-w-10 px-4 text-button-16 [&_svg:not([class*='size-'])]:size-5",
      },
      // Matches Button. `square` (6px) default; `pill` full-radius
      // chip; `circle` full-radius icon-only chip -- aspect-square
      // + !px-0 forces w = h at every size preset.
      shape: {
        square: "rounded-[var(--radius-6)]",
        pill: "rounded-full",
        circle: "rounded-full aspect-square !px-0",
      },
      variant: {
        // Vocabulary aligned with Button: `tertiary` = transparent
        // resting, `secondary` = bordered resting. UX matches the
        // segmented toggle: text goes muted-to-ink on hover and stays
        // ink when pressed; pressed state fills with a neutral surface
        // step (surface-2) so it reads as "depressed" rather than
        // color-inverted. iconMuted keeps icon color story consistent.
        tertiary:
          "bg-transparent text-ink-muted hover:bg-surface-1 hover:text-ink data-[state=on]:bg-surface-2 data-[state=on]:text-ink " +
          iconMuted,
        secondary:
          "bg-transparent text-ink-muted border border-hairline hover:bg-surface-1 hover:text-ink hover:border-hairline-strong data-[state=on]:bg-surface-2 data-[state=on]:text-ink data-[state=on]:border-hairline-strong " +
          iconMuted,
      },
    },
  },
);

export interface ToggleProps
  extends Omit<React.ButtonHTMLAttributes<HTMLButtonElement>, "value" | "defaultValue">,
    VariantProps<typeof toggleVariants> {
  /** Controlled pressed state. */
  pressed?: boolean;
  /** Initial pressed state when uncontrolled. */
  defaultPressed?: boolean;
  /** Called when the pressed state changes. */
  onPressedChange?: (pressed: boolean) => void;
}

/**
 * Toggle: press-to-toggle button with persistent on/off state.
 *
 * Use for actions with binary state: `Bold`/`Italic` in a rich text
 * toolbar, `Star`/`Unstar`, `Mute`/`Unmute`, `Pin`/`Unpin`. Renders with
 * `role="button"` + `aria-pressed` so screen readers announce the state.
 *
 * Note: this is not the same primitive as the pill-shaped Switch.
 * Toggle is a toolbar-style press-to-toggle button; Switch is a
 * slider indicator for a boolean setting.
 */
export function Toggle({
  pressed: controlledPressed,
  defaultPressed = false,
  onPressedChange,
  variant,
  size,
  shape,
  className,
  onClick,
  disabled,
  ...props
}: ToggleProps): React.ReactElement {
  const [uncontrolled, setUncontrolled] = useState(defaultPressed);
  const pressed = controlledPressed ?? uncontrolled;
  const setPressed = useCallback(
    (next: boolean) => {
      if (controlledPressed === undefined) setUncontrolled(next);
      onPressedChange?.(next);
    },
    [controlledPressed, onPressedChange],
  );

  return (
    <button
      type="button"
      aria-pressed={pressed}
      disabled={disabled}
      data-slot="toggle"
      data-state={pressed ? "on" : "off"}
      className={cn(toggleVariants({ variant, size, shape }), className)}
      onClick={(e) => {
        onClick?.(e);
        if (!e.defaultPrevented) setPressed(!pressed);
      }}
      {...props}
    />
  );
}
